    if (monitor.hasChanged('discord_unread', { unread: unread.length, mentionCount })) {
      monitor.send('DISCORD_UNREAD_SUMMARY', {
        unreadChannels: unread.length,
        mentionCount,
        url: location.href,
      });
    }
  }, 2000);

  monitor.watch('[class*="sidebar"]', sendUnreadSummary, {
    observeId: 'sidebar',
    childList: true,
    subtree: true,
    attributes: true,
    attributeFilter: ['class'],
  });

  sendUnreadSummary();
})();

/**
